mapper.select:
SELECT * FROM ( SELECT ROWNUM AS RN, X.* FROM ( SELECT B.BOARD_ID AS id, B.TITLE AS title, NVL(C.CATEGORY_NAME, '-') AS category, NVL(U.NICKNAME, U.USERNAME) AS author, B.REG_DATE AS regDate, ( SELECT COUNT(*) FROM TBL_BOARD A WHERE A.PARENT_ID = B.BOARD_ID AND A.IS_ACTIVE = 'Y' AND A.BOARD_TYPE = 'A' ) AS answerCnt FROM TBL_BOARD B LEFT JOIN TBL_USER U ON U.USER_ID = B.USER_ID LEFT JOIN TBL_CATEGORY C ON C.CATEGORY_ID = B.CATEGORY_ID WHERE B.IS_ACTIVE = 'Y' AND B.BOARD_TYPE = 'Q' AND B.PARENT_ID IS NULL AND ( SELECT COUNT(*) FROM TBL_BOARD A WHERE A.PARENT_ID = B.BOARD_ID AND A.IS_ACTIVE = 'Y' AND A.BOARD_TYPE = 'A' ) = 0
ORDER BY B.REG_DATE ASC, B.BOARD_ID ASC
ORDER BY B.REG_DATE DESC, B.BOARD_ID DESC
) X WHERE ROWNUM <= #{endRow} ) WHERE RN >= #{startRow}
